package entity.session;import java.time.LocalDateTime;import java.util.HashMap;import java.util.List;import java.util.Map;// 补充包路径，与其他实体类保持一致// 导入所需的其他实体类import entity.hall.Hall; // 原代码中CinemaHall应为Hall，保持类名统一import entity.movie.Movie;import entity.seat.Seat;import entity.seat.SeatStatus;import system.CinemaSystem; // 管理器所在包public class Session { // 类名统一为Session    private String showtimeId;    private String movieId;    private String hallId;    private LocalDateTime startTime;    private LocalDateTime endTime;    private double priceCoefficient = 1.0;    private Map<String, SeatStatus> seatStatusMap;    private CinemaSystem cinemaSystem=CinemaSystem.getInstance();    // 构造器类名修正为Session，参数类型修正为Hall    public Session(String showtimeId, String movieId, String hallId, LocalDateTime startTime,                   double priceCoefficient) {        Movie movie=cinemaSystem.getMovieByName(movieId);        this.showtimeId = showtimeId;        this.movieId = movieId;        this.hallId = hallId;        this.startTime = startTime;        this.endTime = startTime.plusMinutes(movie.getDurationMinutes());        this.priceCoefficient = priceCoefficient;        this.seatStatusMap = new HashMap<>();        // 初始化座位状态（修正类名引用和获取方式）        Hall hall = cinemaSystem.getHallById(hallId);        if (hall != null) {            for (Seat seat : hall.getSeatList()) {                seatStatusMap.put(seat.getSeatId(), SeatStatus.AVAILABLE);            }        }    }    // 锁定座位（修正Seat的包引用）    public boolean lockSeats(List<Seat> seats, String orderId) {        for (Seat seat : seats) {            if (!seatStatusMap.containsKey(seat.getSeatId())                    || seatStatusMap.get(seat.getSeatId()) != SeatStatus.AVAILABLE) {                return false;            }        }        for (Seat seat : seats) {            seatStatusMap.put(seat.getSeatId(), SeatStatus.LOCKED);        }        return true;    }    // 解锁座位（统一Seat引用）    public boolean unlockSeats(List<Seat> seats) {        for (Seat seat : seats) {            if (!seatStatusMap.containsKey(seat.getSeatId())                    || seatStatusMap.get(seat.getSeatId()) != SeatStatus.LOCKED) {                return false;            }        }        for (Seat seat : seats) {            seatStatusMap.put(seat.getSeatId(), SeatStatus.AVAILABLE);        }        return true;    }    // 确认座位售出    public boolean confirmSeats(List<Seat> seats) {        for (Seat seat : seats) {            if (!seatStatusMap.containsKey(seat.getSeatId())                    || seatStatusMap.get(seat.getSeatId()) != SeatStatus.LOCKED) {                return false;            }        }        for (Seat seat : seats) {            seatStatusMap.put(seat.getSeatId(), SeatStatus.SOLD);        }        return true;    }    //判断场次是否重叠    public boolean isOverlap(LocalDateTime targetStart, LocalDateTime targetEnd) {        // 重叠规则：目标时间段的开始 < 当前场次结束，且目标时间段的结束 > 当前场次开始        return targetStart.isBefore(this.endTime) && targetEnd.isAfter(this.startTime);    }    // 移除无效的ticketPrice属性（与价格策略冲突）    public String getShowtimeId() { return showtimeId; }    public void setShowtimeId(String showtimeId) { this.showtimeId = showtimeId; }    public String getMovieId() { return movieId; }    public void setMovieId(String movieId) { this.movieId = movieId; }    public String getHallId() { return hallId; }    public void setHallId(String hallId) { this.hallId = hallId; }    public LocalDateTime getStartTime() { return startTime; }    public void setStartTime(LocalDateTime startTime) { this.startTime = startTime; }    public LocalDateTime getEndTime() {        return endTime;    }    public void setEndTime(LocalDateTime endTime) {        this.endTime = endTime;    }    public Map<String, SeatStatus> getSeatStatusMap() { return seatStatusMap; }    public void setSeatStatusMap(Map<String, SeatStatus> seatStatusMap) { this.seatStatusMap = seatStatusMap; }    public double getPriceCoefficient() { return priceCoefficient; }    public void setPriceCoefficient(double priceCoefficient) { this.priceCoefficient = priceCoefficient; }}